SourceCode.Declaration:
/// <summary>
/// This class is an extension of form SalesCopying
/// </summary>
[ExtensionOf(formStr(SalesCopying))]
internal final class ETGSalesCopying_Extension
{
}

Method.Source:
/// <summary>
/// When cylindertracking feature is enabled, then the form controls are visible.
/// </summary>
void  init()
{
    next init();

    FormRun formRun = this as FormRun;
    formRun.design().controlName(FormControlstr(SalesCopying, CustInvoiceTrans_ETGConnectionType)).visible(SalesParameters::find().ETGEnableCylinderTracking);
    formRun.design().controlName(FormControlstr(SalesCopying, CustInvoiceTrans_ETGDepositRate)).visible(SalesParameters::find().ETGEnableCylinderTracking);
    formRun.design().controlName(FormControlstr(SalesCopying, CustInvoiceTrans_ETGCylinderTrackPaymJourCreated)).visible(SalesParameters::find().ETGEnableCylinderTracking);
    formRun.design().controlName(FormControlstr(SalesCopying, CustInvoiceTrans_ETGDepositAmount)).visible(SalesParameters::find().ETGEnableCylinderTracking);
    formRun.design().controlName(FormControlstr(SalesCopying, CustInvoiceTrans_ETGFilledOrEmpty)).visible(SalesParameters::find().ETGEnableCylinderTracking);
    formRun.design().controlName(FormControlstr(SalesCopying, CustInvoiceJour_ETGBusinessSegment)).visible(SalesParameters::find().ETGEnableCylinderTracking);

}
